// // This module selects between two inputs based on the select signal. When s is HIGH (1), out will be assigned the value of in0; otherwise, it will be assigned the value of in1.
module top_module(out, in0, in1, s);input in0;
   input in1;
   input s;
   output out;

   assign out = s ? in1 : in0;
endmodule
